+impl MatrixConnector {
+    #[allow(clippy::too_many_lines)]
+    async fn invoke_inner(&self, req: InvokeRequest) -> FcpResult<InvokeResponse> {
+        let operation = req.operation.as_str();
+
+        if let Some(verifier) = &self.verifier {
+            let required_cap = match operation {
+                OP_JOINED_ROOMS | OP_GET_MESSAGES => CapabilityId::from_static(CAP_READ),
+                OP_SEND_MESSAGE => CapabilityId::from_static(CAP_WRITE),
+                OP_CREATE_ROOM | OP_JOIN_ROOM | OP_LEAVE_ROOM => {
+                    CapabilityId::from_static(CAP_MANAGE)
+                }
+                _ => {
+                    return Err(FcpError::InvalidRequest {
+                        code: 1004,
+                        message: format!("Unknown operation: {operation}"),
+                    })
+                }
+            };
+            verifier.verify(&req.capability_token, &required_cap, &req.operation, &[])?;
+        } else {
+            return Err(FcpError::NotConfigured);
+        }
+
+        let client = self.client.as_ref().ok_or(FcpError::NotConfigured)?;
+
+        let output = match operation {
+            OP_JOINED_ROOMS => {
+                let rooms = client.joined_rooms().await.map_err(|e| e.to_fcp_error())?;
+                json!({ "rooms": rooms })
+            }
+            OP_CREATE_ROOM => {
+                let name = req.input.get("name").and_then(|v| v.as_str()).map(String::from);
+                let topic = req.input.get("topic").and_then(|v| v.as_str()).map(String::from);
+                let invite: Vec<String> = req
+                    .input
+                    .get("invite")
+                    .and_then(|v| serde_json::from_value(v.clone()).ok())
+                    .unwrap_or_default();
+                let visibility = req.input.get("visibility").and_then(|v| v.as_str()).map(String::from);
+                let preset = req.input.get("preset").and_then(|v| v.as_str()).map(String::from);
+
+                let create_req = CreateRoomRequest {
+                    name,
+                    topic,
+                    room_alias_name: None,
+                    invite,
+                    visibility,
+                    preset,
+                };
+                let resp = client.create_room(&create_req).await.map_err(|e| e.to_fcp_error())?;
+                json!({ "room_id": resp.room_id })
+            }
+            OP_JOIN_ROOM => {
+                let room = require_str(&req.input, "room_id_or_alias")?;
+                client.join_room(room).await.map_err(|e| e.to_fcp_error())?;
+                json!({ "status": "joined" })
+            }
+            OP_LEAVE_ROOM => {
+                let room_id = require_str(&req.input, "room_id")?;
+                client.leave_room(room_id).await.map_err(|e| e.to_fcp_error())?;
+                json!({ "status": "left" })
+            }
+            OP_SEND_MESSAGE => {
+                let room_id = require_str(&req.input, "room_id")?;
+                let body = require_str(&req.input, "body")?;
+                let msgtype = req
+                    .input
+                    .get("msgtype")
+                    .and_then(|v| v.as_str())
+                    .unwrap_or("m.text");
+                let resp = client
+                    .send_message(room_id, body, msgtype)
+                    .await
+                    .map_err(|e| e.to_fcp_error())?;
+                json!({ "event_id": resp.event_id })
+            }
+            OP_GET_MESSAGES => {
+                let room_id = require_str(&req.input, "room_id")?;
+                let from = req.input.get("from").and_then(|v| v.as_str());
+                let limit = u32::try_from(
+                    req.input
+                        .get("limit")
+                        .and_then(serde_json::Value::as_u64)
+                        .unwrap_or(20),
+                )
+                .unwrap_or(20);
+                let resp = client
+                    .get_messages(room_id, from, limit)
+                    .await
+                    .map_err(|e| e.to_fcp_error())?;
+                json!({
+                    "messages": resp.chunk,
+                    "end": resp.end,
+                })
+            }
+            _ => {
+                return Err(FcpError::InvalidRequest {
+                    code: 1004,
+                    message: format!("Unknown operation: {operation}"),
+                })
+            }
+        };
+
+        Ok(InvokeResponse::ok(req.id, output))
+    }
+}
